+    #[test]
+    fn deletion_report_tracks_deleted_paths() {
+        let dir = tempfile::tempdir().unwrap();
+
+        let file1 = dir.path().join("a.txt");
+        let file2 = dir.path().join("b.txt");
+        let file3 = dir.path().join("c.txt");
+        fs::write(&file1, "data1").unwrap();
